import {
    getCellsForRectangle,
    isRectangleInsideBoard,
    areCellsEqual,
    getRectangleArea,
    doRectanglesOverlap,
    containsCell,
    Board
} from '../src/index';

describe('Rectangle Placement Helpers', () => {
    it('getCellsForRectangle', () => {
        const cells = getCellsForRectangle({ x: 0, y: 0, width: 2, height: 2 });
        expect(cells).toEqual([
            { x: 0, y: 0 }, { x: 1, y: 0 },
            { x: 0, y: 1 }, { x: 1, y: 1 }
        ]);
    });

    it('isRectangleInsideBoard', () => {
        const board: Board = { width: 4, height: 4, clues: [] };
        expect(isRectangleInsideBoard(board, { x: 0, y: 0, width: 2, height: 2 })).toBe(true);
        expect(isRectangleInsideBoard(board, { x: 3, y: 3, width: 2, height: 2 })).toBe(false);
        expect(isRectangleInsideBoard(board, { x: -1, y: 0, width: 2, height: 2 })).toBe(false);
    });

    it('areCellsEqual', () => {
        expect(areCellsEqual({ x: 1, y: 2 }, { x: 1, y: 2 })).toBe(true);
        expect(areCellsEqual({ x: 1, y: 2 }, { x: 2, y: 1 })).toBe(false);
    });

    it('getRectangleArea', () => {
        expect(getRectangleArea({ x: 0, y: 0, width: 3, height: 4 })).toBe(12);
    });

    it('doRectanglesOverlap', () => {
        const r1 = { x: 0, y: 0, width: 2, height: 2 };
        const r2 = { x: 1, y: 1, width: 2, height: 2 }; // overlaps at 1,1
        const r3 = { x: 2, y: 0, width: 2, height: 2 }; // no overlap
        const r4 = { x: 0, y: 2, width: 2, height: 2 }; // no overlap

        expect(doRectanglesOverlap(r1, r2)).toBe(true);
        expect(doRectanglesOverlap(r1, r3)).toBe(false);
        expect(doRectanglesOverlap(r1, r4)).toBe(false);
    });

    it('containsCell', () => {
        const rect = { x: 1, y: 1, width: 2, height: 2 };
        expect(containsCell(rect, { x: 1, y: 1 })).toBe(true);
        expect(containsCell(rect, { x: 2, y: 2 })).toBe(true);
        expect(containsCell(rect, { x: 0, y: 1 })).toBe(false);
        expect(containsCell(rect, { x: 3, y: 3 })).toBe(false);
    });
});
